debounce.response:
Here's a complete, production-ready solution. The key is to **create the debounced function once** (not inside the event listener) and use an `AbortController` to cancel any in-flight requests if the user keeps typing.

### 1. The Debounce Utility

```javascript
function debounce(func, wait) {
  let timeoutId;

  return function (...args) {
    const context = this;

    clearTimeout(timeoutId);

    timeoutId = setTimeout(() => {
      func.apply(context, args);
    }, wait);
  };
}
```

### 2. Full Working Example

```html
<input type="text" id="search" placeholder="Search..." autocomplete="off" />
<div id="results"></div>
```

```javascript
const searchInput = document.getElementById('search');
const resultsContainer = document.getElementById('results');

// Store AbortController so we can cancel previous requests
let currentAbortController = null;

async function fetchResults(query) {
  // Cancel previous request if it exists
  if (currentAbortController) {
    currentAbortController.abort();
  }

  currentAbortController = new AbortController();

  try {
    resultsContainer.textContent = 'Loading...';

    const response = await fetch(
      `https://api.example.com/search?q=${encodeURIComponent(query)}`,
      { signal: currentAbortController.signal }
    );

    if (!response.ok) throw new Error('Network response was not ok');

    const data = await response.json();
    renderResults(data);

  } catch (error) {
    if (error.name === 'AbortError') {
      // Request was cancelled because user typed more; ignore silently
      return;
    }
    resultsContainer.textContent = 'Error fetching results';
    console.error(error);
  }
}

// Create debounced version ONCE outside the listener
const debouncedSearch = debounce((event) => {
  const query = event.target.value.trim();

  if (!query) {
    resultsContainer.innerHTML = '';
    return;
  }

  fetchResults(query);
}, 300); // 300ms wait after last keystroke

// Attach listener
searchInput.addEventListener('input', debouncedSearch);

// Optional: Cleanup on page unload to prevent memory leaks
window.addEventListener('beforeunload', () => {
  if (currentAbortController) {
    currentAbortController.abort();
  }
});
```

### Key Points

| Pattern | Why It Matters |
|--------|----------------|
| **Define `debounce` once** | If you put `debounce()` inside `addEventListener`, every keystroke creates a new timer and nothing gets debounced. |
| **Use `AbortController`** | Prevents race conditions where an older slow request finishes after a newer fast one, overwriting the results. |
| **Handle `AbortError`** | Don't show error messages to the user when a request is intentionally cancelled. |
| **Trim empty strings** | Avoids firing API calls for whitespace or empty input. |

