function debounce(func, wait) {
  let timeoutId;

  const debounced = function (...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func.apply(this, args), wait);
  };

  debounced.cancel = () => clearTimeout(timeoutId);

  return debounced;
