Here's a clean vanilla JS implementation. The key is wrapping your API call in a **debounce** function that resets a timer on every keystroke:

```javascript
// Reusable debounce utility
function debounce(func, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}

// Your actual search function
async function performSearch(query) {
  if (!query) return;

  console.log('Fetching results for:', query);

  const response = await fetch(`/api/search?q=${encodeURIComponent(query)}`);
  const data = await response.json();
  renderResults(data);
}

// Create debounced version (300ms is a common sweet spot)
const debouncedSearch = debounce(performSearch, 300);

// Attach to input
document.getElementById('search-input').addEventListener('input', (e) => {
  debouncedSearch(e.target.value);
});
```

