                    </div>

                    {/* Right Panel: History */}
                    <div className="glass-panel rounded-3xl p-6 w-full lg:w-1/4 h-64 lg:h-[500px] flex flex-col shadow-2xl z-10">
                        <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                            <div className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></div>
                            Session Log
                        </h2>
                        <div className="flex-1 overflow-y-auto custom-scrollbar space-y-3 pr-2">
                            {history.length === 0 ? (
                                <div className="text-slate-500 text-center mt-10 text-sm italic">
                                    No completed sessions yet.
                                </div>
                            ) : (
                                history.map((item) => (
                                    <div key={item.id} className="bg-slate-800/50 p-3 rounded-lg border border-slate-700/50 flex justify-between items-center hover:bg-slate-800 transition-colors">
                                        <div>
                                            <div className="text-xs text-slate-400 font-mono">{item.completed}</div>
                                            <div className="text-sm font-semibold text-slate-200">{item.label}</div>
                                        </div>
                                        <div className="text-xs font-mono text-emerald-400 bg-emerald-400/10 px-2 py-1 rounded">
                                            {formatTime(item.duration).h !== '00' && formatTime(item.duration).h + ':'}
                                            {formatTime(item.duration).m}:{formatTime(item.duration).s}
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                    </div>

                </div>
            );
        };

        const root = ReactDOM.createRoot(document.getElementById('root'));
        root.render(<CountdownTimer />);
    </script>
</body>
</html>
