                                clearInterval(timerRef.current);
                                setIsRunning(false);
                                setIsWarning(false);
                                playSound('alarm');
                                addLog('Timer Completed');
                                return 0;
                            }
                            if (prev <= 10) {
                                setIsWarning(true);
                                playSound('click'); // Ticking sound
                            }
                            return prev - 1;
