<body>
    <div id="root"></div>

    <script type="text/babel">
        const { useState, useEffect, useRef } = React;

        // --- Audio Context Helper for Browser Autoplay Policy ---
        const playBeep = () => {
            try {
                const AudioContext = window.AudioContext || window.webkitAudioContext;
                if (!AudioContext) return;

                const ctx = new AudioContext();
                const osc = ctx.createOscillator();
                const gain = ctx.createGain();

                osc.connect(gain);
                gain.connect(ctx.destination);

                osc.type = 'sine';
                osc.frequency.value = 880; // A5
                gain.gain.value = 0.1;

                osc.start();
                osc.stop(ctx.currentTime + 0.2);
            } catch (e) {
                console.error("Audio error", e);
            }
        };

        const playAlarm = () => {
            try {
                const AudioContext = window.AudioContext || window.webkitAudioContext;
                if (!AudioContext) return;

                const ctx = new AudioContext();
                const osc = ctx.createOscillator();
                const gain = ctx.createGain();

                osc.connect(gain);
                gain.connect(ctx.destination);

                osc.type = 'square';
                osc.frequency.value = 440; 
                gain.gain.value = 0.1;

                // Siren effect
                osc.frequency.linearRampToValueAtTime(880, ctx.currentTime + 0.5);
                osc.frequency.linearRampToValueAtTime(440, ctx.currentTime + 1.0);

                osc.start();
                osc.stop(ctx.currentTime + 1.0);
            } catch (e) {
                console.error("Audio error", e);
            }
        };

        // --- Main Component ---
        const TimerApp = () => {
            const [timeLeft, setTimeLeft] = useState(0);
            const [initialTime, setInitialTime] = useState(0);
            const [isActive, setIsActive] = useState(false);
            const [isPaused, setIsPaused] = useState(false);
            const [mode, setMode] = useState('setup'); // setup, running, finished
            const [inputHours, setInputHours] = useState(0);
            const [inputMinutes, setInputMinutes] = useState(5);
            const [inputSeconds, setInputSeconds] = useState(0);
            const [taskName, setTaskName] = useState("Focus Session");
            const [showTaskInput, setShowTaskInput] = useState(false);

            const timerRef = useRef(null);

            // Timer Logic
            useEffect(() => {
                if (isActive && !isPaused && timeLeft > 0) {
                    timerRef.current = setInterval(() => {
                        setTimeLeft((prev) => {
                            if (prev <= 1) {
                                clearInterval(timerRef.current);
                                setIsActive(false);
                                setMode('finished');
                                playAlarm();
                                return 0;
                            }
                            return prev - 1;
                        });
                    }, 1000);
                } else {
                    clearInterval(timerRef.current);
                }

                return () => clearInterval(timerRef.current);
            }, [isActive, isPaused, timeLeft]);

            // Formatting
            const formatTime = (totalSeconds) => {
                const h = Math.floor(totalSeconds / 3600);
                const m = Math.floor((totalSeconds % 3600) / 60);
                const s = totalSeconds % 60;
                return `${h > 0 ? h + ':' : ''}${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
            };

            // Controls
