Below is a fully functional React countdown timer component built with hooks. It accepts an initial number of seconds, counts down in real time, and provides controls to start, pause, resume, and reset. You can also pass an optional callback that fires when the timer reaches zero.

```tsx
import React, { useState, useEffect, useRef } from 'react';

/* --------------------- Types --------------------- */
interface CountdownTimerProps {
  /** Number of seconds to count down from */
  initialSeconds: number;
  /** Called when the timer reaches 0 */
  onComplete?: () => void;
  /** Whether the timer should start automatically on mount (default: true) */
  autoStart?: boolean;
}

/* --------------------- Component --------------------- */
const CountdownTimer: React.FC<CountdownTimerProps> = ({
  initialSeconds,
  onComplete,
  autoStart = true,
}) => {
  const [timeLeft, setTimeLeft] = useState(initialSeconds);
  const [isRunning, setIsRunning] = useState(autoStart);
  const [isPaused, setIsPaused] = useState(false);

  const intervalRef = useRef<NodeJS.Timeout | null>(null);
  const onCompleteRef = useRef(onComplete);
  onCompleteRef.current = onComplete;

  // Reset timer when initialSeconds or autoStart changes
  useEffect(() => {
    setTimeLeft(initialSeconds);
    setIsRunning(autoStart);
    setIsPaused(false);
  }, [initialSeconds, autoStart]);

  // Main interval logic
  useEffect(() => {
    // Only start interval if running, not paused, and time remains
    if (isRunning && !isPaused && timeLeft > 0) {
      intervalRef.current = setInterval(() => {
        setTimeLeft((prev) => {
          if (prev <= 1) {
            // Timer finished
            clearInterval(intervalRef.current!);
            onCompleteRef.current?.();
            setIsRunning(false);
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }

    // Cleanup on state change or unmount
    return () => {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
    };
  }, [isRunning, isPaused]); // intentionally omit timeLeft

  // ---------- Controls ----------
  const start = () => {
    setTimeLeft((prev) => (prev <= 0 ? initialSeconds : prev));
    setIsRunning(true);
    setIsPaused(false);
  };

  const togglePause = () => {
    setIsPaused((prev) => !prev);
  };

  const reset = () => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    setTimeLeft(initialSeconds);
    setIsRunning(false);
    setIsPaused(false);
  };

  // ---------- Formatting ----------
  const formatTime = (totalSeconds: number): string => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${String(mins).padStart(2, '0')}:${String(secs).padStart(2, '0')}`;
  };

  // ---------- Render ----------
  return (
    <div style={{ textAlign: 'center', fontFamily: 'monospace' }}>
      <div style={{ fontSize: '3rem', margin: '1rem 0' }}>
        {formatTime(timeLeft)}
      </div>

      <div>
        {(!isRunning || isPaused) && timeLeft > 0 && (
          <button onClick={start} style={buttonStyle}>
            Start
          </button>
        )}
        {isRunning && !isPaused && (
          <button onClick={togglePause} style={buttonStyle}>
            Pause
          </button>
        )}
        {isPaused && (
          <button onClick={togglePause} style={buttonStyle}>
            Resume
          </button>
        )}
        <button onClick={reset} style={buttonStyle}>
          Reset
        </button>
      </div>
    </div>
  );
};

/* --------------------- Styles --------------------- */
const buttonStyle: React.CSSProperties = {
  margin: '0 0.5rem',
  padding: '0.5rem 1.2rem',
  fontSize: '1rem',
  cursor: 'pointer',
  border: '1px solid #ccc',
  borderRadius: '4px',
  background: '#f5f5f5',
};

export default CountdownTimer;
```

