Here's a versatile React countdown timer component with start, pause, reset functionality, precise time tracking, and cleanup. It accepts an initial number of seconds and provides an optional callback when the countdown completes.

```tsx
import React, { useState, useEffect, useRef, useCallback } from 'react';

interface CountdownTimerProps {
  initialSeconds: number;
  onComplete?: () => void;
  autoStart?: boolean;
  format?: 'mm:ss' | 'hh:mm:ss';
  className?: string;
}

const formatTime = (totalSeconds: number, format: 'mm:ss' | 'hh:mm:ss' = 'mm:ss'): string => {
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;

  const pad = (num: number) => String(num).padStart(2, '0');

  if (format === 'hh:mm:ss' || hours > 0) {
    return `${pad(hours)}:${pad(minutes)}:${pad(seconds)}`;
  }
  return `${pad(minutes)}:${pad(seconds)}`;
};

const CountdownTimer: React.FC<CountdownTimerProps> = ({
  initialSeconds,
  onComplete,
  autoStart = true,
  format = 'mm:ss',
  className,
}) => {
  const [remainingSeconds, setRemainingSeconds] = useState(initialSeconds);
  const [isRunning, setIsRunning] = useState(autoStart);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const onCompleteRef = useRef(onComplete);
  const endTimeRef = useRef<number>(0);

  // Keep the callback ref updated
  useEffect(() => {
    onCompleteRef.current = onComplete;
  }, [onComplete]);

  // Sync remainingSeconds when initialSeconds changes (if not running)
  useEffect(() => {
    if (!isRunning) {
      setRemainingSeconds(initialSeconds);
    }
  }, [initialSeconds, isRunning]);

  // Core countdown logic using date-based precision
  useEffect(() => {
    if (isRunning && remainingSeconds > 0) {
      // Calculate the exact end time when starting/resuming
      endTimeRef.current = Date.now() + remainingSeconds * 1000;

      intervalRef.current = setInterval(() => {
        const now = Date.now();
        const remaining = Math.max(0, Math.round((endTimeRef.current - now) / 1000));

        setRemainingSeconds(remaining);

        if (remaining <= 0) {
          clearInterval(intervalRef.current!);
          intervalRef.current = null;
          setIsRunning(false);
          onCompleteRef.current?.();
        }
      }, 200); // Check more frequently for better accuracy
    } else if (!isRunning || remainingSeconds <= 0) {
      // Cleanup interval if paused or completed
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
    }

    return () => {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
    };
  }, [isRunning]); // Restart effect when isRunning changes

  const start = useCallback(() => {
    if (remainingSeconds > 0) setIsRunning(true);
  }, [remainingSeconds]);

  const pause = useCallback(() => setIsRunning(false), []);

  const reset = useCallback(() => {
    setIsRunning(false);
    setRemainingSeconds(initialSeconds);
  }, [initialSeconds]);

  const toggle = useCallback(() => {
    if (remainingSeconds <= 0) {
      reset();
      setIsRunning(true); // auto-start after reset
    } else {
      setIsRunning(prev => !prev);
    }
  }, [remainingSeconds, reset]);

  return (
    <div className={`countdown-timer ${className || ''}`} role="timer" aria-live="polite">
      <div className="time-display" style={{ fontSize: '2em', fontVariantNumeric: 'tabular-nums' }}>
        {formatTime(remainingSeconds, format)}
      </div>
      <div className="controls" style={{ marginTop: '0.5em' }}>
        <button onClick={start} disabled={isRunning || remainingSeconds <= 0}>
          Start
        </button>
        <button onClick={pause} disabled={!isRunning}>
          Pause
        </button>
        <button onClick={reset}>
          Reset
        </button>
        <button onClick={toggle}>
          {isRunning ? 'Pause' : remainingSeconds <= 0 ? 'Restart' : 'Start'}
        </button>
      </div>
    </div>
  );
};

export default CountdownTimer;
```

