# React Countdown Timer Component

Here's a fully-featured, styled countdown timer component with start/pause/reset controls and a circular progress ring.

## `CountdownTimer.jsx`

```jsx
import React, { useState, useEffect, useCallback, useRef } from "react";

const CountdownTimer = ({
  initialSeconds = 60,
  onComplete = () => {},
  size = 200,
  strokeWidth = 8,
  autoStart = false,
}) => {
  const [timeLeft, setTimeLeft] = useState(initialSeconds);
  const [isRunning, setIsRunning] = useState(autoStart);
  const [isComplete, setIsComplete] = useState(false);
  const intervalRef = useRef(null);

  // --- Core timer logic ---
  useEffect(() => {
    if (isRunning && timeLeft > 0) {
      intervalRef.current = setInterval(() => {
        setTimeLeft((prev) => {
          if (prev <= 1) {
            clearInterval(intervalRef.current);
            setIsRunning(false);
            setIsComplete(true);
            onComplete();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }

    return () => clearInterval(intervalRef.current);
  }, [isRunning, timeLeft > 0, onComplete]);

  // --- Controls ---
  const start = () => {
    if (timeLeft > 0 && !isComplete) {
      setIsRunning(true);
    }
  };

  const pause = () => {
    setIsRunning(false);
  };

  const reset = () => {
    clearInterval(intervalRef.current);
    setTimeLeft(initialSeconds);
    setIsRunning(false);
    setIsComplete(false);
  };

  // --- Formatting ---
  const formatTime = (totalSeconds) => {
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    const seconds = totalSeconds % 60;

    if (hours > 0) {
      return `${String(hours).padStart(2, "0")}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
    }
    return `${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
  };

  // --- Circular progress math ---
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;
  const progress = timeLeft / initialSeconds;
  const strokeDashoffset = circumference * (1 - progress);

  // --- Dynamic color based on remaining time ---
  const getColor = () => {
    if (isComplete) return "#ef4444";
    if (progress <= 0.1) return "#ef4444"; // red
    if (progress <= 0.25) return "#f97316"; // orange
    if (progress <= 0.5) return "#eab308"; // yellow
    return "#3b82f6"; // blue
  };

  const color = getColor();

  return (
    <div style={styles.container}>
      {/* SVG Ring */}
      <div style={{ position: "relative", width: size, height: size }}>
        <svg
          width={size}
          height={size}
          style={{ transform: "rotate(-90deg)" }}
        >
          {/* Background circle */}
          <circle
            cx={size / 2}
            cy={size / 2}
            r={radius}
            fill="none"
            stroke="#1e293b"
            strokeWidth={strokeWidth}
          />
          {/* Progress circle */}
          <circle
            cx={size / 2}
            cy={size / 2}
            r={radius}
            fill="none"
            stroke={color}
            strokeWidth={strokeWidth}
            strokeDasharray={circumference}
            strokeDashoffset={strokeDashoffset}
            strokeLinecap="round"
            style={{
              transition: "stroke-dashoffset 0.5s ease, stroke 0.5s ease",
            }}
          />
        </svg>

        {/* Time display overlaid on the ring */}
        <div style={styles.timeOverlay}>
          <span
            style={{
              ...styles.timeText,
              fontSize: size * 0.2,
              color: isComplete ? "#ef4444" : "#f8fafc",
            }}
          >
            {formatTime(timeLeft)}
          </span>
          <span style={styles.label}>
            {isComplete
              ? "Time's up!"
              : isRunning
                ? "Running"
                : timeLeft < initialSeconds
                  ? "Paused"
                  : "Ready"}
          </span>
        </div>
      </div>

      {/* Controls */}
      <div style={styles.controls}>
        {!isRunning && !isComplete && (
          <button
            onClick={start}
            style={{ ...styles.button, ...styles.startButton }}
            onMouseEnter={(e) =>
              (e.currentTarget.style.transform = "scale(1.05)")
            }
            onMouseLeave={(e) =>
              (e.currentTarget.style.transform = "scale(1)")
            }
          >
            ▶ Start
          </button>
        )}

        {isRunning && (
          <button
            onClick={pause}
            style={{ ...styles.button, ...styles.pauseButton }}
            onMouseEnter={(e) =>
              (e.currentTarget.style.transform = "scale(1.05)")
            }
            onMouseLeave={(e) =>
              (e.currentTarget.style.transform = "scale(1)")
            }
          >
            ⏸ Pause
          </button>
        )}

        <button
          onClick={reset}
          style={{ ...styles.button, ...styles.resetButton }}
          onMouseEnter={(e) =>
            (e.currentTarget.style.transform = "scale(1.05)")
          }
          onMouseLeave={(e) =>
            (e.currentTarget.style.transform = "scale(1)")
          }
        >
          ↺ Reset
        </button>
      </div>
    </div>
  );
};

// --- Styles ---
const styles = {
  container: {
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    gap: "24px",
    padding: "40px",
    borderRadius: "20px",
    background: "linear-gradient(145deg, #0f172a, #1e293b)",
    boxShadow: "0 25px 50px rgba(0, 0, 0, 0.4)",
    fontFamily:
      "'SF Mono', 'Fira Code', 'Cascadia Code', 'Consolas', monospace",
  },
  timeOverlay: {
    position: "absolute",
    top: 0,
    left: 0,
    width: "100%",
    height: "100%",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
    gap: "4px",
  },
  timeText: {
    fontWeight: "700",
    letterSpacing: "2px",
    lineHeight: 1,
  },
  label: {
    fontSize: "12px",
    color: "#94a3b8",
    textTransform: "uppercase",
    letterSpacing: "2px",
    fontWeight: "500",
  },
  controls: {
    display: "flex",
    gap: "12px",
  },
  button: {
    padding: "12px 28px",
    fontSize: "14px",
    fontWeight: "600",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer",
    letterSpacing: "0.5px",
    transition: "all 0.2s ease",
    color: "#ffffff",
  },
  startButton: {
    background: "linear-gradient(135deg, #3b82f6, #2563eb)",
    boxShadow: "0 4px 15px rgba(59, 130, 246, 0.4)",
  },
  pauseButton: {
    background: "linear-gradient(135deg, #f97316, #ea580c)",
    boxShadow: "0 4px 15px rgba(249, 115, 22, 0.4)",
  },
  resetButton: {
    background: "linear-gradient(135deg, #475569, #334155)",
    boxShadow: "0 4px 15px rgba(71, 85, 105, 0.3)",
  },
};

export default CountdownTimer;
```

## Usage in `App.jsx`

```jsx
import React from "react";
import CountdownTimer from "./CountdownTimer";

export default function App() {
  const handleComplete = () => {
    alert("⏰ Timer finished!");
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: "48px",
        background: "#0f172a",
      }}
    >
      <h1 style={{ color: "#f8fafc", fontFamily: "sans-serif" }}>
        Countdown Timer
      </h1>

      {/* Basic 60-second timer */}
      <CountdownTimer initialSeconds={60} onComplete={handleComplete} />

      {/* Larger 5-minute timer */}
      <CountdownTimer
        initialSeconds={300}
        size={250}
        strokeWidth={10}
        onComplete={() => console.log("5 min done!")}
      />

      {/* Auto-starting 10-second timer */}
      <CountdownTimer
        initialSeconds={10}
        autoStart={true}
        size={150}
        strokeWidth={6}
      />
    </div>
  );
