# Debouncing a Search Input in Vanilla JavaScript

Here's a clean implementation with explanations:

## The Core Idea

Debounce delays a function call until a specified time has passed *without* another invocation. Each new keystroke resets the timer, so the API only fires once the user stops typing.

## Implementation

```html
<input type="text" id="search" placeholder="Search...">
```

```javascript
function debounce(fn, delay) {
  let timeoutId;

  return function (...args) {
    // Clear any pending invocation
    clearTimeout(timeoutId);

    // Schedule a new one
    timeoutId = setTimeout(() => {
      fn.apply(this, args);
    }, delay);
  };
}

// Your API call function
async function fetchResults(query) {
  if (!query.trim()) return;
  const response = await fetch(`/api/search?q=${encodeURIComponent(query)}`);
  const data = await response.json();
  console.log('Results:', data);
  // renderResults(data);
}

// Wrap it with debounce — 300ms feels snappy and avoids most redundant calls
const debouncedSearch = debounce(fetchResults, 300);

// Wire it up
const input = document.getElementById('search');
input.addEventListener('input', (e) => {
  debouncedSearch(e.target.value);
});
```

## Why 300ms?

- **Under 200ms**: Not much benefit; the user is still actively typing.
- **200–400ms**: Sweet spot. Feels instant but cuts most bursts.
- **Over 500ms**: Feels laggy for fast typists.

## Optional Enhancements

**1. Cancel in-flight requests** (avoid race conditions where an older slow response overwrites a newer one):

```javascript
function debounceAsync(fn, delay) {
  let timeoutId;
  let controller;

  return function (...args) {
    clearTimeout(timeoutId);

    timeoutId = setTimeout(async () => {
      // Abort any previous request
      if (controller) controller.abort();
      controller = new AbortController();

      try {
        await fn(controller.signal, ...args);
      } catch (err) {
        if (err.name !== 'AbortError') throw err;
      }
    }, delay);
  };
}

async function fetchResults(signal, query) {
  if (!query.trim()) return;
  const response = await fetch(`/api/search?q=${encodeURIComponent(query)}`, { signal });
  const data = await response.json();
  console.log('Results:', data);
}

const debouncedSearch = debounceAsync(fetchResults, 300);
```

**2. Add a leading-edge trigger** (fire immediately on first keystroke, then debounce subsequent ones — useful when the input might be empty initially):

```javascript
function debounce(fn, delay, { leading = false } = {}) {
  let timeoutId;
  let called = false;

  return function (...args) {
    if (leading && !called) {
      fn.apply(this, args);
      called = true;
    }

    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      called = false;
      if (!leading) fn.apply(this, args);
    }, delay);
  };
}
```

The basic version at the top covers 90% of search-input cases. Add request cancellation if you find stale results appearing when the user keeps typing.

# Debounced Search Input in Vanilla JavaScript

Here's a clean implementation that delays the API call until the user stops typing:

## Basic Implementation

```javascript
const searchInput = document.getElementById('search-input');
let debounceTimer;

searchInput.addEventListener('input', (e) => {
  clearTimeout(debounceTimer);

  debounceTimer = setTimeout(() => {
    performSearch(e.target.value);
  }, 300);
});

function performSearch(query) {
  fetch(`/api/search?q=${encodeURIComponent(query)}`)
    .then(res => res.json())
    .then(data => renderResults(data))
    .catch(err => console.error(err));
}
```

## Reusable Debounce Utility

For multiple inputs, extract the logic:

```javascript
function debounce(fn, delay = 300) {
  let timer;
  return function (...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}

const searchInput = document.getElementById('search-input');

const handleSearch = debounce((query) => {
  fetch(`/api/search?q=${encodeURIComponent(query)}`)
    .then(res => res.json())
    .then(renderResults)
    .catch(console.error);
}, 300);

searchInput.addEventListener('input', (e) => handleSearch(e.target.value));
```

## Full Version with Loading & Error States

```javascript
function debounce(fn, delay) {
  let timer;
  return function (...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}

const searchInput = document.getElementById('search-input');
const resultsContainer = document.getElementById('results');
let activeRequest;

const handleSearch = debounce(async (query) => {
  // Abort previous request if still in flight
  if (activeRequest) activeRequest.abort();

  // Empty query → clear results
  if (!query.trim()) {
    resultsContainer.innerHTML = '';
    return;
  }

  // Show loading state
  resultsContainer.innerHTML = '<p>Searching...</p>';

  try {
    const controller = new AbortController();
    activeRequest = controller;

    const res = await fetch(`/api/search?q=${encodeURIComponent(query)}`, {
      signal: controller.signal
    });

    if (!res.ok) throw new Error(`HTTP ${res.status}`);

    const data = await res.json();
    renderResults(data);
  } catch (err) {
    if (err.name === 'AbortError') return; // expected
    resultsContainer.innerHTML = `<p class="error">Error: ${err.message}</p>`;
  }
}, 300);

searchInput.addEventListener('input', (e) => handleSearch(e.target.value));

function renderResults(data) {
  if (!data.length) {
    resultsContainer.innerHTML = '<p>No results found.</p>';
    return;
  }
  resultsContainer.innerHTML = data
    .map(item => `<li>${item.title}</li>`)
    .join('');
}
```

## Key Points

| Concern | Solution |
|---------|----------|
| **Excess API calls** | `setTimeout` delays execution until typing pauses |
| **Rapid typing** | `clearTimeout` cancels pending calls on each keystroke |
| **Stale responses** | `AbortController` cancels in-flight requests |
| **Reusability** | Higher-order `debounce()` function |
| **UX feedback** | Loading & empty states |

## Tuning the Delay

- **100–200ms** — feels instant, good for fast autocomplete
- **300ms** — balanced (most common default)
- **500ms+** — when the API is expensive or rate-limited

The 300ms sweet spot matches typical user typing pauses and feels responsive without flooding your API.

# Debouncing a Search Input

Here's how to add debouncing to your search input so the API only fires after the user stops typing.

## Core Implementation

```javascript
function debounce(fn, delay) {
  let timeoutId;
  return function (...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      fn.apply(this, args);
    }, delay);
  };
}

const searchInput = document.getElementById('search');
const resultsList = document.getElementById('results');

async function fetchResults(query) {
  if (!query) {
    resultsList.innerHTML = '';
    return;
  }
  try {
    const res = await fetch(`/api/search?q=${encodeURIComponent(query)}`);
    const data = await res.json();
    renderResults(data);
  } catch (err) {
    console.error('Search failed:', err);
  }
}

const debouncedSearch = debounce(fetchResults, 300);

searchInput.addEventListener('input', (e) => {
  debouncedSearch(e.target.value);
});
```

## What's Happening

- **`debounce(fn, delay)`** returns a wrapper that clears any pending timer on each call and only invokes `fn` once the user pauses for `delay` ms.
- `fetchResults` only runs when the debounce timer fires, not on every keystroke.
- `encodeURIComponent` keeps the query safe in the URL.

## Optional Enhancements

**1. Cancel in-flight requests when a new one starts** — useful if results could arrive out of order:

```javascript
function debounceAsync(fn, delay) {
  let timeoutId;
  let controller;

  return function (...args) {
    clearTimeout(timeoutId);
    controller?.abort();
    controller = new AbortController();

    return new Promise((resolve, reject) => {
      timeoutId = setTimeout(async () => {
        try {
          const result = await fn(...args, controller.signal);
          resolve(result);
        } catch (err) {
          if (err.name !== 'AbortError') reject(err);
        }
      }, delay);
    });
  };
}

async function fetchResults(query, signal) {
  const res = await fetch(`/api/search?q=${encodeURIComponent(query)}`, { signal });
  return res.json();
}

const debouncedSearch = debounceAsync(fetchResults, 300);
```

**2. Show a loading state** for queries over a threshold:

```javascript
let loadingTimer;
searchInput.addEventListener('input', (e) => {
  clearTimeout(loadingTimer);
  loadingTimer = setTimeout(() => {
    resultsList.classList.add('loading');
  }, 200); // show spinner if request takes >200ms to fire
  debouncedSearch(e.target.value).finally(() => {
    resultsList.classList.remove('loading');
  });
});
```

**3. Minimum query length** to avoid wasted requests:

```javascript
const debouncedSearch = debounce((query) => {
  if (query.length < 2) return;
  fetchResults(query);
}, 300);
```

## Choosing a Delay

| Delay | Use case |
|-------|----------|
| 150–200 ms | Feels instant, great for small datasets |
| 300 ms | Good default for most APIs |
| 500 ms | Heavy endpoints, expensive operations |

Start with **300 ms** and adjust based on how snappy it feels.

