# Countdown Timer Component in React

Here's a clean, reusable countdown timer component with start, pause, and reset functionality:

```jsx
import React, { useState, useEffect, useRef } from 'react';

const CountdownTimer = ({ initialSeconds = 60, onComplete }) => {
  const [seconds, setSeconds] = useState(initialSeconds);
  const [isRunning, setIsRunning] = useState(false);
  const intervalRef = useRef(null);
  const onCompleteRef = useRef(onComplete);

  // Keep the latest onComplete callback in a ref
  useEffect(() => {
    onCompleteRef.current = onComplete;
  }, [onComplete]);

  useEffect(() => {
    if (isRunning && seconds > 0) {
      intervalRef.current = setInterval(() => {
        setSeconds((prev) => {
          if (prev <= 1) {
            setIsRunning(false);
            if (onCompleteRef.current) {
              onCompleteRef.current();
            }
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }

    return () => {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
      }
    };
  }, [isRunning]);

  const handleStart = () => setIsRunning(true);
  const handlePause = () => setIsRunning(false);
  const handleReset = () => {
    setIsRunning(false);
    setSeconds(initialSeconds);
  };

  // Format seconds as MM:SS
  const formatTime = (totalSeconds) => {
    const minutes = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${String(minutes).padStart(2, '0')}:${String(secs).padStart(2, '0')}`;
  };

  return (
    <div style={styles.container}>
      <div style={styles.display}>{formatTime(seconds)}</div>
      <div style={styles.controls}>
        {!isRunning ? (
          <button onClick={handleStart} disabled={seconds === 0} style={styles.button}>
            Start
          </button>
        ) : (
          <button onClick={handlePause} style={styles.button}>
            Pause
          </button>
        )}
        <button onClick={handleReset} style={styles.button}>
          Reset
        </button>
      </div>
      {seconds === 0 && <p style={styles.completeText}>Time's up!</p>}
    </div>
  );
};

const styles = {
  container: {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    padding: '20px',
    fontFamily: 'sans-serif',
  },
  display: {
    fontSize: '64px',
    fontWeight: 'bold',
    marginBottom: '20px',
    fontVariantNumeric: 'tabular-nums',
  },
  controls: {
    display: 'flex',
    gap: '10px',
  },
  button: {
    padding: '10px 20px',
    fontSize: '16px',
    cursor: 'pointer',
    border: '1px solid #ccc',
    borderRadius: '4px',
    background: '#fff',
  },
  completeText: {
    marginTop: '15px',
    color: '#d9534f',
    fontWeight: 'bold',
  },
};

export default CountdownTimer;
```

## Usage Example

```jsx
import React from 'react';
import CountdownTimer from './CountdownTimer';

const App = () => {
  const handleComplete = () => {
    console.log('Countdown finished!');
    // Trigger sound, notification, modal, etc.
  };

  return (
    <div>
      <h1>My Countdown Timer</h1>
      <CountdownTimer
        initialSeconds={120}
        onComplete={handleComplete}
      />
    </div>
  );
};

export default App;
```

## Key Features

- **Configurable duration** via the `initialSeconds` prop
- **Start/Pause/Reset** controls
- **MM:SS formatting** for readability
- **Completion callback** via the `onComplete` prop
- **Clean state management** with proper interval cleanup to prevent memory leaks
- **Auto-stops** when reaching zero

## How It Works

1. The `useState` hook tracks remaining seconds and running state
2. A `useEffect` hook sets up the interval when running, with cleanup on unmount or when stopped
3. When the timer hits zero, it stops automatically and fires the `onComplete` callback
4. The `useRef` for the callback ensures we always use the latest version without re-running the effect

You can easily extend this by adding props for custom styling, labels, or a "tick" callback for progress tracking.

# React Countdown Timer Component

Here's a clean, reusable countdown timer component:

```jsx
import { useState, useEffect, useRef } from 'react';

function CountdownTimer({ initialSeconds = 60, onComplete }) {
  const [secondsLeft, setSecondsLeft] = useState(initialSeconds);
  const [isRunning, setIsRunning] = useState(false);
  const intervalRef = useRef(null);
  const onCompleteRef = useRef(onComplete);

  // Keep the latest onComplete callback without restarting the interval
  useEffect(() => {
    onCompleteRef.current = onComplete;
  }, [onComplete]);

  useEffect(() => {
    if (!isRunning) return;

    intervalRef.current = setInterval(() => {
      setSecondsLeft((prev) => {
        if (prev <= 1) {
          clearInterval(intervalRef.current);
          setIsRunning(false);
          onCompleteRef.current?.();
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(intervalRef.current);
  }, [isRunning]);

  const start = () => {
    if (secondsLeft > 0) setIsRunning(true);
  };

  const pause = () => {
    setIsRunning(false);
    clearInterval(intervalRef.current);
  };

  const reset = (newSeconds = initialSeconds) => {
    pause();
    setSecondsLeft(newSeconds);
  };

  const formatTime = (totalSeconds) => {
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;
    return `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
  };

  return (
    <div style={{ fontFamily: 'monospace', textAlign: 'center' }}>
      <h1 style={{ fontSize: '4rem', margin: '0' }}>{formatTime(secondsLeft)}</h1>
      <div style={{ marginTop: '1rem' }}>
        <button onClick={start} disabled={isRunning || secondsLeft === 0}>
          Start
        </button>{' '}
        <button onClick={pause} disabled={!isRunning}>
          Pause
        </button>{' '}
        <button onClick={() => reset()}>Reset</button>
      </div>
    </div>
  );
}

export default CountdownTimer;
