# Countdown Timer Component in React

Here's a complete, reusable countdown timer component with start, pause, and reset functionality.

## CountdownTimer.jsx

```jsx
import React, { useState, useEffect, useRef } from 'react';

const CountdownTimer = ({ initialSeconds = 60, onComplete }) => {
  const [seconds, setSeconds] = useState(initialSeconds);
  const [isRunning, setIsRunning] = useState(false);
  const intervalRef = useRef(null);

  useEffect(() => {
    if (isRunning && seconds > 0) {
      intervalRef.current = setInterval(() => {
        setSeconds((prev) => {
          if (prev <= 1) {
            setIsRunning(false);
            if (onComplete) onComplete();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }

    return () => clearInterval(intervalRef.current);
  }, [isRunning, seconds, onComplete]);

  const handleStart = () => {
    if (seconds > 0) setIsRunning(true);
  };

  const handlePause = () => setIsRunning(false);

  const handleReset = () => {
    setIsRunning(false);
    setSeconds(initialSeconds);
  };

  const formatTime = (totalSeconds) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${String(mins).padStart(2, '0')}:${String(secs).padStart(2, '0')}`;
  };

  const isFinished = seconds === 0;

  return (
    <div style={styles.container}>
      <h2 style={styles.title}>Countdown Timer</h2>

      <div style={{
        ...styles.display,
        color: seconds <= 10 && seconds > 0 ? '#e74c3c' : '#2c3e50',
      }}>
        {formatTime(seconds)}
      </div>

      {isFinished && <p style={styles.finishedText}>Time's up! 🎉</p>}

      <div style={styles.buttonGroup}>
        <button
          onClick={handleStart}
          disabled={isRunning || isFinished}
          style={{ ...styles.button, ...styles.startButton }}
        >
          Start
        </button>

        <button
          onClick={handlePause}
          disabled={!isRunning}
          style={{ ...styles.button, ...styles.pauseButton }}
        >
          Pause
        </button>

        <button
          onClick={handleReset}
          style={{ ...styles.button, ...styles.resetButton }}
        >
          Reset
        </button>
      </div>
    </div>
  );
};

const styles = {
  container: {
    fontFamily: 'system-ui, sans-serif',
    textAlign: 'center',
    padding: '2rem',
    maxWidth: '400px',
    margin: '2rem auto',
    border: '2px solid #ecf0f1',
    borderRadius: '12px',
    boxShadow: '0 4px 12px rgba(0,0,0,0.08)',
    backgroundColor: '#fff',
  },
  title: {
    margin: '0 0 1rem',
    color: '#34495e',
    fontSize: '1.5rem',
  },
  display: {
    fontSize: '4rem',
    fontWeight: 'bold',
    fontVariantNumeric: 'tabular-nums',
    margin: '1.5rem 0',
    transition: 'color 0.3s ease',
  },
  finishedText: {
    color: '#27ae60',
    fontSize: '1.2rem',
    margin: '0.5rem 0',
  },
  buttonGroup: {
    display: 'flex',
    gap: '0.5rem',
    justifyContent: 'center',
    flexWrap: 'wrap',
  },
  button: {
    padding: '0.6rem 1.2rem',
    fontSize: '1rem',
    border: 'none',
    borderRadius: '6px',
    cursor: 'pointer',
    color: '#fff',
    fontWeight: '600',
    transition: 'opacity 0.2s ease, transform 0.1s ease',
  },
  startButton: { backgroundColor: '#27ae60' },
  pauseButton: { backgroundColor: '#f39c12' },
  resetButton: { backgroundColor: '#95a5a6' },
};

export default CountdownTimer;
